  ('heelevel3-10ced7e2-moex-00240', 'heelevel3-10ced7e2', 'heelevel3-10ced7e2-moex-111-3082b5f1', 'sub-heelevel3-10ced7e2-04', NULL, 'single_choice', '關於行政法法源之敘述，下列何者正確？', '["緊急命令係取代或暫停法律之規範，故其不得作為行政法之法源", "法規命令規範事項雖屬行政機關內部事務，但仍可作為行政法之法源", "由立法院審議通過產生國內法律效力後，係屬行政法之法源", "行政規則在對人民權利有所限制時，才能例外作為行政法法源 31350、31450 32050、32750 32850 33550"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:35+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "320", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "人事行政"}'::jsonb, NULL),
